class Solution:
    def buyChoco(self, prices, money):
        n = len(prices)
        best = None
        for i in range(n):
            for j in range(i + 1, n):
                s = prices[i] + prices[j]
                if best is None or s < best:
                    best = s
        if best is not None and best <= money:
            return money - best
        return money

