var buyChoco = function(prices, money) {
    let first = Infinity, second = Infinity;
    for (const p of prices) {
        if (p < first) {
            second = first;
            first = p;
        } else if (p < second) {
            second = p;
        }
    }
    const total = first + second;
    return total <= money ? money - total : money;
};
